import requests

def test_cheque_deposit_missing_image_returns_400(auth_token, api_base_url):
    data = {'cheque_amount': 1000}
    headers = {'Authorization': f'Bearer {auth_token}'}

    resp = requests.post(
        f'{api_base_url}/deposits/mobile-cheque',
        data=data,
        headers=headers
    )

    assert resp.status_code == 400
    payload = resp.json()
    assert 'error' in payload or 'message' in payload
